use super::{InnerIntersectionBuilder, IntersectionBuilder};
use crate::Db;
use crate::types::Type;
use crate::types::tuple::{TupleSpec, TupleSpecBuilder, TupleType};
use crate::types::visitor::any_over_type;
use rustc_hash::FxHashSet;

/// Maximum number of tuple alternatives generated by indexed-protocol complements.
const MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES: usize = 64;

/// Maximum total number of tuple elements copied into generated alternatives.
const MAX_INDEXED_PROTOCOL_COMPLEMENT_ELEMENTS: usize = 4_096;

/// Return whether tuple or protocol elements can be refined set-theoretically.
///
/// Dynamic types can be hidden behind aliases, so checking only the top-level types is insufficient.
fn all_elements_are_static(db: &dyn Db, elements: &[Type<'_>]) -> bool {
    elements
        .iter()
        .all(|element| !any_over_type(db, *element, true, |ty| ty.is_dynamic()))
}

/// Build an intersection used while simplifying indexed-protocol complements.
///
/// This can simplify ordinary intersections, but must leave nested indexed-protocol complements
/// symbolic so that the outer fixed-point pass remains in control.
fn build_indexed_protocol_simplification_intersection<'db>(
    db: &'db dyn Db,
    positives: impl IntoIterator<Item = Type<'db>>,
    negatives: impl IntoIterator<Item = Type<'db>>,
) -> Type<'db> {
    let mut builder = IntersectionBuilder::new(db).positive_elements(positives);
    for negative in negatives {
        builder = builder.add_negative(negative);
    }
    builder.build_without_indexed_protocol_simplification()
}

/// Result of subtracting one finite indexed protocol from an exact tuple.
#[derive(Debug, Eq, PartialEq)]
enum TupleProtocolComplement<'db> {
    /// The tuple or protocol contains gradual or unsupported element types.
    NotApplicable,
    /// The tuple is already disjoint from the protocol, so the complement adds no constraint.
    Redundant,
    /// Every tuple value satisfies the protocol, so its complement eliminates the branch.
    Eliminated,
    /// Each entry identifies a tuple position and the element type that violates the protocol.
    Alternatives(Vec<(usize, Type<'db>)>),
}

/// A synthesized protocol and its decoded element constraint for each exact index.
struct IndexedProtocolConstraint<'db> {
    protocol: Type<'db>,
    elements: Box<[Type<'db>]>,
}

/// The combined exact-tuple view of all tuple positives in one intersection branch.
///
/// `positive_indices` records which original positives must be replaced when the combined tuple is
/// refined or expanded.
struct StaticTupleIntersection<'db> {
    positive_indices: Vec<usize>,
    tuple: TupleSpec<'db>,
}

/// A preflighted replacement of one intersection branch with exact-tuple alternatives.
///
/// Materialization removes `handled_protocols` and the tuple positives represented by
/// `positive_indices`, then inserts one tuple positive for each element vector.
struct IndexedProtocolExpansion<'db> {
    handled_protocols: Vec<Type<'db>>,
    positive_indices: Vec<usize>,
    alternatives: Vec<Vec<Type<'db>>>,
}

/// Refine a tuple specialization using finite indexed constraints from a protocol.
///
/// Returns `None` when `ty` is not a tuple specialization, `Some(Never)` when the tuple shape is
/// disjoint from the protocol, and the refined tuple type otherwise.
///
/// This intentionally assumes that tuple subclasses preserve the relationship between iteration
/// and indexing provided by the builtin `tuple` class. A tuple subclass can override `__iter__` so
/// that a sequence pattern observes different element types than inherited indexing does, making
/// this refinement unsound for that subclass. We accept this limitation to retain precise
/// narrowing for ordinary tuple annotations.
fn refine_tuple_with_indexed_protocol<'db>(
    db: &'db dyn Db,
    ty: Type<'db>,
    protocol_elements: &[Type<'db>],
) -> Option<Type<'db>> {
    if !all_elements_are_static(db, protocol_elements) {
        return None;
    }

    let Type::NominalInstance(instance) = ty else {
        return None;
    };

    let tuple = instance.own_tuple_spec(db)?;
    if !all_elements_are_static(db, tuple.all_elements()) {
        return None;
    }

    let protocol_tuple = TupleSpec::heterogeneous(protocol_elements.iter().copied());
    let Some(refined) = TupleSpecBuilder::from(tuple.as_ref()).intersect(db, &protocol_tuple)
    else {
        return Some(Type::Never);
    };

    Some(Type::tuple(TupleType::new(db, &refined.build())))
}

/// Internalize a finite indexed protocol's element constraints into an exact tuple type.
///
/// For example:
///
/// ```python
/// def narrow(value: tuple[int | str, int | str]) -> None:
///     match value:
///         case [_, str()]:
///             reveal_type(value)  # tuple[int | str, str]
/// ```
pub(super) fn refine_tuple_protocol_intersection<'db>(
    db: &'db dyn Db,
    left: Type<'db>,
    right: Type<'db>,
) -> Option<Type<'db>> {
    let ((Type::ProtocolInstance(protocol), tuple) | (tuple, Type::ProtocolInstance(protocol))) =
        (left, right)
    else {
        return None;
    };
    let indexed = protocol.finite_indexed_constraint(db)?;
    refine_tuple_with_indexed_protocol(db, tuple, &indexed)
}

/// Analyze subtraction of finite indexed constraints from a fixed-length tuple type.
///
/// A complement with one unresolved position can be represented by refining that tuple element.
/// Complements with multiple unresolved positions require a union with one alternative per
/// position. Returns an error before constructing more than `max_alternatives` changes.
fn tuple_protocol_complement<'db>(
    db: &'db dyn Db,
    tuple: &TupleSpec<'db>,
    protocol_elements: &[Type<'db>],
    max_alternatives: usize,
) -> Result<TupleProtocolComplement<'db>, ()> {
    if !all_elements_are_static(db, protocol_elements) {
        return Ok(TupleProtocolComplement::NotApplicable);
    }

    let TupleSpec::Fixed(tuple) = tuple else {
        return Ok(TupleProtocolComplement::NotApplicable);
    };
    if !all_elements_are_static(db, tuple.all_elements()) {
        return Ok(TupleProtocolComplement::NotApplicable);
    }

    if tuple.len() != protocol_elements.len() {
        return Ok(TupleProtocolComplement::Redundant);
    }

    let mut alternatives = Vec::new();
    for (index, (element, protocol_element)) in tuple
        .all_elements()
        .iter()
        .zip(protocol_elements)
        .enumerate()
    {
        if element.is_disjoint_from(db, *protocol_element) {
            return Ok(TupleProtocolComplement::Redundant);
        }
        if element.is_subtype_of(db, *protocol_element) {
            continue;
        }

        let remaining_element =
            build_indexed_protocol_simplification_intersection(db, [*element], [*protocol_element]);
        if remaining_element.is_never() {
            continue;
        }
        if alternatives.len() == max_alternatives {
            return Err(());
        }
        alternatives.push((index, remaining_element));
    }

    Ok(if alternatives.is_empty() {
        TupleProtocolComplement::Eliminated
    } else {
        TupleProtocolComplement::Alternatives(alternatives)
    })
}

impl<'db> IntersectionBuilder<'db> {
    /// Simplify finite indexed-protocol complements against exact tuple constraints.
    ///
    /// Unit clauses are propagated to a fixed point before ambiguous complements are expanded.
    /// Expansion is all-or-nothing across the builder: if the aggregate alternative or copied
    /// element budget is exceeded, ambiguous complements remain symbolic while propagated
    /// refinements are preserved.
    pub(super) fn simplify_indexed_protocol_negatives(mut self) -> Self {
        let protocols = self.indexed_protocol_constraints();
        if protocols.is_empty() {
            return self;
        }

        let db = self.db;
        self.intersections = self
            .intersections
            .into_iter()
            .filter_map(|inner| inner.simplify_indexed_protocol_negatives(db, &protocols))
            .collect();

        let Ok(expansions) = self
            .intersections
            .iter()
            .map(|inner| inner.indexed_protocol_expansion(db, &protocols))
            .collect::<Result<Vec<_>, ()>>()
        else {
            return self;
        };

        let mut total_alternatives = 0usize;
        let mut total_elements = 0usize;
        for expansion in &expansions {
            total_alternatives = total_alternatives.saturating_add(
                expansion
                    .as_ref()
                    .map_or(1, |expansion| expansion.alternatives.len()),
            );
            total_elements =
                total_elements.saturating_add(expansion.as_ref().map_or(0, |expansion| {
                    expansion.alternatives.iter().map(Vec::len).sum()
                }));
            if total_alternatives > MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES
                || total_elements > MAX_INDEXED_PROTOCOL_COMPLEMENT_ELEMENTS
            {
                return self;
            }
        }

        self.intersections = self
            .intersections
            .into_iter()
            .zip(expansions)
            .flat_map(|(inner, expansion)| match expansion {
                Some(expansion) => inner.materialize_indexed_protocol_expansion(db, expansion),
                None => vec![inner],
            })
            .collect();
        self
    }

    /// Collect the static finite indexed protocols used as negatives in any branch.
    ///
    /// Constraints are deduplicated and sorted by their displayed element types so fixed-point
    /// propagation and bounded expansion do not depend on insertion order.
    fn indexed_protocol_constraints(&self) -> Vec<IndexedProtocolConstraint<'db>> {
        let mut seen_protocols = FxHashSet::default();
        let mut constraints = Vec::new();

        for negative in self
            .intersections
            .iter()
            .flat_map(|inner| inner.negative.iter())
        {
            let Type::ProtocolInstance(protocol) = negative else {
                continue;
            };
            if !seen_protocols.insert(*negative) {
                continue;
            }
            let Some(elements) = protocol.finite_indexed_constraint(self.db) else {
                continue;
            };
            if !all_elements_are_static(self.db, &elements) {
                continue;
            }
            constraints.push(IndexedProtocolConstraint {
                protocol: *negative,
                elements,
            });
        }

        constraints.sort_by_cached_key(|constraint| {
            constraint
                .elements
                .iter()
                .map(|element| element.display(self.db).to_string())
                .collect::<Box<[_]>>()
        });
        constraints
    }
}

impl<'db> InnerIntersectionBuilder<'db> {
    /// Intersect every static exact-tuple positive in this branch.
    ///
    /// The returned indices identify the positives represented by the combined tuple so callers
    /// can replace them without discarding unrelated positive constraints.
    fn static_tuple_intersection(
        &self,
        db: &'db dyn Db,
    ) -> Result<Option<StaticTupleIntersection<'db>>, ()> {
        let mut positive_indices = Vec::new();
        let mut intersection: Option<TupleSpecBuilder<'db>> = None;

        for (positive_index, positive) in self.positive.iter().enumerate() {
            let Type::NominalInstance(instance) = positive else {
                continue;
            };
            let Some(tuple) = instance.own_tuple_spec(db) else {
                continue;
            };
            if !all_elements_are_static(db, tuple.all_elements()) {
                continue;
            }

            positive_indices.push(positive_index);
            intersection = Some(match intersection {
                Some(intersection) => intersection.intersect(db, tuple.as_ref()).ok_or(())?,
                None => TupleSpecBuilder::from(tuple.as_ref()),
            });
        }

        let Some(intersection) = intersection else {
            return Ok(None);
        };
        let intersection = intersection.build();
        if let TupleSpec::Fixed(tuple) = &intersection
            && tuple.all_elements().iter().any(Type::is_never)
        {
            return Err(());
        }
        Ok(Some(StaticTupleIntersection {
            positive_indices,
            tuple: intersection,
        }))
    }

    /// Propagate unambiguous indexed-protocol complements to a fixed point within one branch.
    ///
    /// A complement with one unresolved tuple position refines that element directly. Redundant
    /// complements are removed, an eliminated branch returns `None`, and complements requiring a
    /// union remain for the bounded expansion phase.
    fn simplify_indexed_protocol_negatives(
        mut self,
        db: &'db dyn Db,
        protocols: &[IndexedProtocolConstraint<'db>],
    ) -> Option<Self> {
        loop {
            let mut changed = false;

            for constraint in protocols {
                if !self.negative.contains(&constraint.protocol) {
                    continue;
                }

                let intersection = match self.static_tuple_intersection(db) {
                    Ok(Some(intersection)) => intersection,
                    Ok(None) => continue,
                    Err(()) => return None,
                };
                match tuple_protocol_complement(db, &intersection.tuple, &constraint.elements, 2) {
                    Err(()) | Ok(TupleProtocolComplement::NotApplicable) => continue,
                    Ok(TupleProtocolComplement::Redundant) => {}
                    Ok(TupleProtocolComplement::Eliminated) => return None,
                    Ok(TupleProtocolComplement::Alternatives(alternatives)) => {
                        let [(index, remaining_element)] = alternatives.as_slice() else {
                            continue;
                        };
                        let TupleSpec::Fixed(tuple) = &intersection.tuple else {
                            continue;
                        };
                        let mut elements = tuple.all_elements().to_vec();
                        elements[*index] = *remaining_element;
                        for positive_index in intersection.positive_indices.into_iter().rev() {
                            self.positive.swap_remove_index(positive_index);
                        }
                        self.add_positive(db, Type::heterogeneous_tuple(db, elements));
                        if self.positive.contains(&Type::Never) {
                            return None;
                        }
                    }
                }
                self.negative.swap_remove(&constraint.protocol);
                changed = true;
            }

            if !changed {
                return Some(self);
            }
        }
    }

    /// Preflight bounded expansion of the branch's remaining ambiguous tuple complements.
    ///
    /// This computes tuple element vectors without mutating the branch. Returning an error causes
    /// the outer builder to retain all ambiguous complements symbolically.
    fn indexed_protocol_expansion(
        &self,
        db: &'db dyn Db,
        protocols: &[IndexedProtocolConstraint<'db>],
    ) -> Result<Option<IndexedProtocolExpansion<'db>>, ()> {
        let Ok(Some(intersection)) = self.static_tuple_intersection(db) else {
            return Ok(None);
        };
        let TupleSpec::Fixed(tuple) = &intersection.tuple else {
            return Ok(None);
        };

        let mut handled_protocols = Vec::new();
        let mut alternatives = vec![tuple.all_elements().to_vec()];

        for constraint in protocols {
            if !self.negative.contains(&constraint.protocol) {
                continue;
            }
            let Ok(TupleProtocolComplement::Alternatives(tuple_alternatives)) =
                tuple_protocol_complement(
                    db,
                    &intersection.tuple,
                    &constraint.elements,
                    MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES,
                )
            else {
                continue;
            };
            if tuple_alternatives.len() < 2 {
                continue;
            }

            let mut expanded = Vec::new();
            let mut seen = FxHashSet::default();
            for elements in &alternatives {
                for (index, remaining_element) in &tuple_alternatives {
                    let mut elements = elements.clone();
                    let element = build_indexed_protocol_simplification_intersection(
                        db,
                        [elements[*index], *remaining_element],
                        [],
                    );
                    if element.is_never() {
                        continue;
                    }
                    elements[*index] = element;
                    if !seen.insert(elements.clone()) {
                        continue;
                    }
                    if expanded.len() == MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES
                        || expanded
                            .len()
                            .saturating_add(1)
                            .saturating_mul(elements.len())
                            > MAX_INDEXED_PROTOCOL_COMPLEMENT_ELEMENTS
                    {
                        return Err(());
                    }
                    expanded.push(elements);
                }
            }

            handled_protocols.push(constraint.protocol);
            alternatives = expanded;
            if alternatives.is_empty() {
                break;
            }
        }

        if handled_protocols.is_empty() {
            return Ok(None);
        }
        Ok(Some(IndexedProtocolExpansion {
            handled_protocols,
            positive_indices: intersection.positive_indices,
            alternatives,
        }))
    }

    /// Apply a preflighted expansion without repeating complement analysis.
    ///
    /// Each generated branch retains unrelated positive and negative constraints. Alternatives
    /// that become uninhabited after reinsertion are discarded.
    fn materialize_indexed_protocol_expansion(
        self,
        db: &'db dyn Db,
        expansion: IndexedProtocolExpansion<'db>,
    ) -> Vec<Self> {
        let mut alternatives = Vec::with_capacity(expansion.alternatives.len());
        for elements in expansion.alternatives {
            let mut alternative = self.clone();
            for protocol in &expansion.handled_protocols {
                alternative.negative.swap_remove(protocol);
            }
            for positive_index in expansion.positive_indices.iter().rev() {
                alternative.positive.swap_remove_index(*positive_index);
            }
            alternative.add_positive(db, Type::heterogeneous_tuple(db, elements));
            if !alternative.positive.contains(&Type::Never) {
                alternatives.push(alternative);
            }
        }
        alternatives
    }
}

#[cfg(test)]
mod tests {
    use super::{
        IntersectionBuilder, MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES,
        MAX_INDEXED_PROTOCOL_COMPLEMENT_ELEMENTS, TupleProtocolComplement,
        tuple_protocol_complement,
    };
    use crate::db::tests::{TestDb, setup_db};
    use crate::types::match_pattern::exact_sequence_pattern_type;
    use crate::types::tuple::TupleSpec;
    use crate::types::{KnownClass, Type, UnionType};

    fn exact_sequence_protocol<'db>(db: &'db TestDb, elements: &[Type<'db>]) -> Type<'db> {
        let Type::Intersection(pattern) = exact_sequence_pattern_type(db, elements.iter().copied())
        else {
            panic!("Expected exact sequence pattern to be an intersection");
        };
        *pattern
            .positive(db)
            .iter()
            .find(|positive| matches!(positive, Type::ProtocolInstance(_)))
            .expect("Expected exact sequence pattern to contain a protocol")
    }

    #[test]
    fn tuple_protocol_complement_returns_position_alternatives() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let tuple = TupleSpec::heterogeneous([element, element]);

        assert_eq!(
            tuple_protocol_complement(&db, &tuple, &[int, str], 2),
            Ok(TupleProtocolComplement::Alternatives(vec![
                (0, str),
                (1, int)
            ]))
        );
    }

    #[test]
    fn tuple_protocol_complements_propagate_to_fixed_point() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let tuple = Type::heterogeneous_tuple(&db, [UnionType::from_two_elements(&db, int, str)]);
        let int_protocol = exact_sequence_protocol(&db, &[int]);
        let str_protocol = exact_sequence_protocol(&db, &[str]);

        for [first, second] in [[int_protocol, str_protocol], [str_protocol, int_protocol]] {
            let result = IntersectionBuilder::new(&db)
                .add_positive(tuple)
                .add_negative(first)
                .add_negative(second)
                .build();
            assert!(result.is_never());
        }
    }

    #[test]
    fn ambiguous_tuple_protocol_complement_expands() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let tuple = Type::heterogeneous_tuple(&db, [element, element]);
        let protocol = exact_sequence_protocol(&db, &[int, str]);
        let expected = UnionType::from_elements(
            &db,
            [
                Type::heterogeneous_tuple(&db, [str, element]),
                Type::heterogeneous_tuple(&db, [element, int]),
            ],
        );

        let result = IntersectionBuilder::new(&db)
            .add_positive(tuple)
            .add_negative(protocol)
            .build();
        assert!(result.is_equivalent_to(&db, expected));
    }

    #[test]
    fn tuple_protocol_complement_expands_cartesian_product() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let tuple = Type::heterogeneous_tuple(&db, [element; 4]);
        let first_protocol =
            exact_sequence_protocol(&db, &[int, int, Type::object(), Type::object()]);
        let second_protocol =
            exact_sequence_protocol(&db, &[Type::object(), Type::object(), str, str]);
        let expected = UnionType::from_elements(
            &db,
            [
                Type::heterogeneous_tuple(&db, [str, element, int, element]),
                Type::heterogeneous_tuple(&db, [str, element, element, int]),
                Type::heterogeneous_tuple(&db, [element, str, int, element]),
                Type::heterogeneous_tuple(&db, [element, str, element, int]),
            ],
        );

        let result = IntersectionBuilder::new(&db)
            .add_positive(tuple)
            .add_negative(first_protocol)
            .add_negative(second_protocol)
            .build();
        assert!(result.is_equivalent_to(&db, expected));
    }

    #[test]
    fn tuple_protocol_complement_expands_at_limits() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let length = MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES;
        assert_eq!(length * length, MAX_INDEXED_PROTOCOL_COMPLEMENT_ELEMENTS);
        let tuple = Type::heterogeneous_tuple(&db, std::iter::repeat_n(element, length));
        let protocol = exact_sequence_protocol(&db, &vec![int; length]);

        let result = IntersectionBuilder::new(&db)
            .add_positive(tuple)
            .add_negative(protocol)
            .build();
        let Type::Union(result) = result else {
            panic!("Expected tuple complement at the limits to expand");
        };
        assert_eq!(result.elements(&db).len(), length);
    }

    #[test]
    fn tuple_protocol_complement_over_alternative_limit_remains_symbolic() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let length = MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES + 1;
        let tuple = Type::heterogeneous_tuple(&db, std::iter::repeat_n(element, length));
        let protocol = exact_sequence_protocol(&db, &vec![int; length]);

        let result = IntersectionBuilder::new(&db)
            .add_positive(tuple)
            .add_negative(protocol)
            .build();
        let Type::Intersection(result) = result else {
            panic!("Expected ambiguous tuple complement to remain symbolic");
        };
        assert!(result.negative(&db).contains(&protocol));
    }

    #[test]
    fn tuple_protocol_complement_over_element_limit_remains_symbolic() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let length = MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES + 1;
        let tuple = Type::heterogeneous_tuple(&db, std::iter::repeat_n(element, length));
        let refined_tuple = Type::heterogeneous_tuple(
            &db,
            std::iter::once(int).chain(std::iter::repeat_n(element, length - 1)),
        );
        let refining_protocol = exact_sequence_protocol(
            &db,
            &std::iter::once(str)
                .chain(std::iter::repeat_n(Type::object(), length - 1))
                .collect::<Vec<_>>(),
        );
        let expansive_protocol = exact_sequence_protocol(&db, &vec![int; length]);

        for [first, second] in [
            [refining_protocol, expansive_protocol],
            [expansive_protocol, refining_protocol],
        ] {
            let result = IntersectionBuilder::new(&db)
                .add_positive(tuple)
                .add_negative(first)
                .add_negative(second)
                .build();
            let Type::Intersection(result) = result else {
                panic!("Expected tuple complement over the element limit to remain symbolic");
            };
            assert!(result.positive(&db).contains(&refined_tuple));
            assert!(result.negative(&db).contains(&expansive_protocol));
            assert!(!result.negative(&db).contains(&refining_protocol));
        }
    }

    #[test]
    fn tuple_protocol_complement_limit_is_shared_across_union_arms() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let bytes = KnownClass::Bytes.to_instance(&db);
        let length = MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES / 2 + 1;
        let tuple_with_str = Type::heterogeneous_tuple(
            &db,
            std::iter::repeat_n(UnionType::from_two_elements(&db, int, str), length),
        );
        let tuple_with_bytes = Type::heterogeneous_tuple(
            &db,
            std::iter::repeat_n(UnionType::from_two_elements(&db, int, bytes), length),
        );
        let protocol = exact_sequence_protocol(&db, &vec![int; length]);

        let result = IntersectionBuilder::new(&db)
            .add_positive(UnionType::from_two_elements(
                &db,
                tuple_with_str,
                tuple_with_bytes,
            ))
            .add_negative(protocol)
            .build();
        let Type::Union(result) = result else {
            panic!("Expected union arms over the shared limit to remain separate");
        };
        assert_eq!(result.elements(&db).len(), 2);
        assert!(result.elements(&db).iter().all(|element| {
            let Type::Intersection(intersection) = element else {
                return false;
            };
            intersection.negative(&db).contains(&protocol)
        }));
    }

    #[test]
    fn unchanged_union_arms_count_toward_tuple_protocol_complement_limit() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let length = MAX_INDEXED_PROTOCOL_COMPLEMENT_ALTERNATIVES;
        let expansive = Type::heterogeneous_tuple(
            &db,
            std::iter::repeat_n(UnionType::from_two_elements(&db, int, str), length),
        );
        let unchanged = Type::heterogeneous_tuple(&db, [str]);
        let protocol = exact_sequence_protocol(&db, &vec![int; length]);

        let result = IntersectionBuilder::new(&db)
            .add_positive(UnionType::from_two_elements(&db, expansive, unchanged))
            .add_negative(protocol)
            .build();
        let Type::Union(result) = result else {
            panic!("Expected tuple complement over the shared limit to remain symbolic");
        };
        assert_eq!(result.elements(&db).len(), 2);
        assert!(result.elements(&db).contains(&unchanged));
        assert!(result.elements(&db).iter().any(|element| {
            let Type::Intersection(intersection) = element else {
                return false;
            };
            intersection.negative(&db).contains(&protocol)
        }));
    }

    #[test]
    fn eliminating_tuple_protocol_precedes_ambiguous_constraints() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let length = 8;
        let tuple = Type::heterogeneous_tuple(&db, std::iter::repeat_n(element, length));
        let int_protocol = exact_sequence_protocol(&db, &vec![int; length]);
        let str_protocol = exact_sequence_protocol(&db, &vec![str; length]);
        let object_protocol = exact_sequence_protocol(&db, &vec![Type::object(); length]);

        for protocols in [
            [int_protocol, str_protocol, object_protocol],
            [int_protocol, object_protocol, str_protocol],
            [str_protocol, int_protocol, object_protocol],
            [str_protocol, object_protocol, int_protocol],
            [object_protocol, int_protocol, str_protocol],
            [object_protocol, str_protocol, int_protocol],
        ] {
            let result = IntersectionBuilder::new(&db)
                .add_positive(tuple)
                .add_negative(protocols[0])
                .add_negative(protocols[1])
                .add_negative(protocols[2])
                .build();
            assert!(result.is_never());
        }
    }

    #[test]
    fn tuple_protocol_complement_considers_all_positive_tuples() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let int_or_str = UnionType::from_two_elements(&db, int, str);
        let expansive = Type::heterogeneous_tuple(&db, [int_or_str, int_or_str]);
        let disjoint = Type::heterogeneous_tuple(&db, [str, Type::object()]);
        let protocol = exact_sequence_protocol(&db, &[int, int]);
        let build = |first, second, negative| {
            let mut builder = IntersectionBuilder::new(&db)
                .add_positive(first)
                .add_positive(second);
            if negative {
                builder = builder.add_negative(protocol);
            }
            builder.build()
        };

        for [first, second] in [[expansive, disjoint], [disjoint, expansive]] {
            let result = build(first, second, true);
            assert!(result.is_equivalent_to(&db, build(first, second, false)));
            let Type::Intersection(result) = result else {
                panic!("Expected both tuple constraints to remain in an intersection");
            };
            assert!(!result.negative(&db).contains(&protocol));
        }
    }

    #[test]
    fn tuple_protocol_complement_combines_positive_tuple_constraints() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let bytes = KnownClass::Bytes.to_instance(&db);
        let int_or_str = UnionType::from_two_elements(&db, int, str);
        let first_tuple = Type::heterogeneous_tuple(&db, [int_or_str, int_or_str]);
        let second_tuple = Type::heterogeneous_tuple(
            &db,
            [UnionType::from_two_elements(&db, int, bytes), int_or_str],
        );
        let expected = Type::heterogeneous_tuple(&db, [int, str]);
        let protocol = exact_sequence_protocol(&db, &[int, int]);

        for [first, second] in [[first_tuple, second_tuple], [second_tuple, first_tuple]] {
            let result = IntersectionBuilder::new(&db)
                .add_positive(first)
                .add_positive(second)
                .add_negative(protocol)
                .build();
            assert!(result.is_equivalent_to(&db, expected));
        }
    }

    #[test]
    fn simplification_keeps_nested_complement_symbolic() {
        let db = setup_db();
        let int = KnownClass::Int.to_instance(&db);
        let str = KnownClass::Str.to_instance(&db);
        let element = UnionType::from_two_elements(&db, int, str);
        let length = 8;
        let tuple = Type::heterogeneous_tuple(&db, std::iter::repeat_n(element, length));
        let protocol = exact_sequence_protocol(&db, &vec![int; length]);
        let remaining =
            super::build_indexed_protocol_simplification_intersection(&db, [tuple], [protocol]);

        let Type::Intersection(remaining) = remaining else {
            panic!("Expected nested tuple complement to remain symbolic");
        };
        assert!(remaining.negative(&db).contains(&protocol));
    }
}
